export declare const SUPPLIER_REMITTANCE_HTML =
  '<!DOCTYPE html>\n<html lang="en">\n<head>\n  <meta charset="UTF-8" />\n  <title>Remittance Advice {{document.number}}</title>\n  <style>\n    /* Remittance-specific overrides */\n    .remittance-details {\n      display: flex;\n      justify-content: space-between;\n      align-items: flex-start;\n      margin-bottom: 20px;\n    }\n    .remittance-details .left {\n      flex: 1;\n    }\n    .remittance-details .right {\n      flex: 0 0 auto;\n    }\n    .allocations-table {\n      width: 100%;\n      border-collapse: collapse;\n      margin-bottom: 16px;\n    }\n    .allocations-table thead th {\n      background: #f0f0f0;\n      font-size: 10px;\n      font-weight: 700;\n      text-transform: uppercase;\n      color: #555;\n      padding: 8px 6px;\n      border-bottom: 2px solid #ccc;\n      text-align: left;\n    }\n    .allocations-table thead th.text-right {\n      text-align: right;\n    }\n    .allocations-table tbody td {\n      padding: 6px;\n      border-bottom: 1px solid #e5e5e5;\n      font-size: 11px;\n      vertical-align: top;\n    }\n    .allocations-table tbody td.text-right {\n      text-align: right;\n    }\n    .allocations-table tbody tr:nth-child(even) {\n      background: #f9f9f9;\n    }\n    .total-paid {\n      margin-left: auto;\n      width: 280px;\n      margin-bottom: 20px;\n      page-break-inside: avoid;\n    }\n    .total-paid table {\n      width: 100%;\n      border-collapse: collapse;\n    }\n    .total-paid td {\n      padding: 4px 0;\n      font-size: 11px;\n    }\n    .total-paid td:last-child {\n      text-align: right;\n      font-variant-numeric: tabular-nums;\n    }\n    .total-paid .total-row {\n      font-weight: 700;\n      font-size: 14px;\n      border-top: 2px solid #333;\n      padding-top: 8px;\n      color: #111;\n    }\n  </style>\n</head>\n<body>\n  <div class="page">\n\n    \n<div class="header">\n  <div class="header-left">\n    {{#if branding.showLogo}}\n    {{#if company.logoUrl}}\n    <div class="logo-section">\n      <img src="{{company.logoUrl}}" alt="{{company.name}} logo" />\n    </div>\n    {{/if}}\n    {{/if}}\n    <div class="company-name">{{company.name}}</div>\n    {{#if company.legalName}}\n    <div class="company-legal-name">{{company.legalName}}</div>\n    {{/if}}\n  </div>\n  <div class="header-right">\n    <div class="company-details">\n      <p style="white-space:pre-line">{{company.address}}</p>\n      {{#if company.phone}}<p>Tel: {{company.phone}}</p>{{/if}}\n      {{#if company.email}}<p>{{company.email}}</p>{{/if}}\n      {{#if company.website}}<p>{{company.website}}</p>{{/if}}\n      {{#if branding.showVatNumber}}\n      {{#if company.vatNumber}}<p class="vat-number">VAT: {{company.vatNumber}}</p>{{/if}}\n      {{/if}}\n      {{#if branding.showCompanyReg}}\n      {{#if company.companyNumber}}<p class="company-reg">Reg: {{company.companyNumber}}</p>{{/if}}\n      {{/if}}\n    </div>\n  </div>\n</div>\n\n    <div class="document-title">Remittance Advice</div>\n\n    <div class="remittance-details">\n      <div class="left">\n        <div class="address-block">\n          <div class="label">To</div>\n          <div class="name">{{counterparty.name}}</div>\n          <div class="address">{{counterparty.address}}</div>\n        </div>\n      </div>\n      <div class="right">\n        <div class="document-details">\n          <table>\n            <tr><th>Remittance No.</th><td>{{document.number}}</td></tr>\n            <tr><th>Payment Date</th><td>{{formatDate document.date}}</td></tr>\n            {{#if document.reference}}\n            <tr><th>Payment Ref.</th><td>{{document.reference}}</td></tr>\n            {{/if}}\n            {{#if metadata.paymentMethod}}\n            <tr><th>Payment Method</th><td>{{metadata.paymentMethod}}</td></tr>\n            {{/if}}\n          </table>\n        </div>\n      </div>\n    </div>\n\n    <table class="allocations-table">\n      <thead>\n        <tr>\n          <th style="width:120px">Invoice No.</th>\n          <th style="width:100px">Invoice Date</th>\n          <th>Description</th>\n          <th class="text-right" style="width:110px">Invoice Amount</th>\n          <th class="text-right" style="width:110px">Amount Paid</th>\n        </tr>\n      </thead>\n      <tbody>\n        {{#each lines}}\n        <tr class="line-item-row">\n          <td>{{this.itemCode}}</td>\n          <td>{{formatDate this.date}}</td>\n          <td>{{this.description}}</td>\n          <td class="text-right">{{formatCurrency this.unitPrice ../metadata.currencyCode}}</td>\n          <td class="text-right">{{formatCurrency this.lineTotal ../metadata.currencyCode}}</td>\n        </tr>\n        {{/each}}\n      </tbody>\n    </table>\n\n    <div class="total-paid">\n      <table>\n        <tr class="total-row">\n          <td>Total Paid</td>\n          <td>{{formatCurrency totals.total metadata.currencyCode}}</td>\n        </tr>\n      </table>\n    </div>\n\n    \n{{#if branding.showBankDetails}}\n<div class="bank-details">\n  <div class="section-title">Bank Details</div>\n  <table>\n    {{#if company.bankName}}\n    <tr><td>Bank</td><td>{{company.bankName}}</td></tr>\n    {{/if}}\n    {{#if company.bankSortCode}}\n    <tr><td>Sort Code</td><td>{{company.bankSortCode}}</td></tr>\n    {{/if}}\n    {{#if company.bankAccountNumber}}\n    <tr><td>Account No.</td><td>{{company.bankAccountNumber}}</td></tr>\n    {{/if}}\n  </table>\n</div>\n{{/if}}\n\n    <div class="notice notice-info">\n      If you have any queries regarding this payment, please contact our accounts\n      department at {{#if company.email}}{{company.email}}{{else}}the details shown above{{/if}}.\n    </div>\n\n    {{#if document.notes}}\n    <div class="notes-section">\n      <div class="section-title">Notes</div>\n      {{document.notes}}\n    </div>\n    {{/if}}\n\n    \n<div class="page-footer">\n  {{company.name}} &mdash; Generated by Nexa ERP\n  <div class="page-numbers">Page <span class="pageNumber"></span> of <span class="totalPages"></span></div>\n</div>\n\n  </div>\n</body>\n</html>';
